('Asteroid Worm', 'A silicon-based organism that burrows through asteroids, emerging to consume ships.', 'raid', 'common', 7200, 100, 60, 35, '["Tunnel Strike", "Rock Shell"]'::jsonb, '{"explosive": 1.3}'::jsonb, '{"kinetic": 0.5}'::jsonb, '[{"item": "silicon_core", "quantity": 1, "dropRate": 0.5}]'::jsonb, '{"xp": 180, "credits": 400, "resources": {"metal": 80, "crystal": 60}}'::jsonb, 6, 1, 1),
('Plasma Leech', 'An energy parasitic organism that drains power from ship systems on contact.', 'raid', 'common', 5800, 80, 20, 65, '["Energy Drain", "Plasma Burst"]'::jsonb, '{"kinetic": 1.4}'::jsonb, '{"energy": 0.5}'::jsonb, '[{"item": "plasma_residue", "quantity": 4, "dropRate": 0.75}]'::jsonb, '{"xp": 160, "credits": 350, "resources": {"metal": 40, "crystal": 80}}'::jsonb, 5, 1, 1),
('Rust Raider', 'A desperate pirate operating a barely-functional fighter in the outer rim.', 'raid', 'common', 7000, 110, 35, 40, '["Grappling Hook", "Boarding Party"]'::jsonb, '{"explosive": 1.4}'::jsonb, '{"energy": 0.8}'::jsonb, '[{"item": "pirate_creds", "quantity": 200, "dropRate": 0.9}]'::jsonb, '{"xp": 200, "credits": 500, "resources": {"metal": 90, "crystal": 30, "deuterium": 20}}'::jsonb, 7, 1, 1),
('Ion Storm Phantom', 'A ghostly energy signature that manifests as a hostile entity during ion storms.', 'raid', 'common', 6200, 95, 30, 50, '["Ion Overload", "Phase Shift"]'::jsonb, '{"kinetic": 1.6}'::jsonb, '{"energy": 0.4}'::jsonb, '[{"item": "ion_crystal", "quantity": 2, "dropRate": 0.65}]'::jsonb, '{"xp": 170, "credits": 380, "resources": {"crystal": 100, "deuterium": 30}}'::jsonb, 6, 1, 1),
('Cargo Raider Drone', 'A small automated drone designed to hijack cargo ships in trade lanes.', 'raid', 'common', 5500, 85, 25, 60, '["EMP Pulse", "Cargo Snatch"]'::jsonb, '{"explosive": 1.5}'::jsonb, '{"kinetic": 0.7}'::jsonb, '[{"item": "drone_parts", "quantity": 3, "dropRate": 0.7}]'::jsonb, '{"xp": 140, "credits": 320, "resources": {"metal": 70, "crystal": 40}}'::jsonb, 5, 1, 1),
