('Nebula Crawler', 'A biological ship-like organism that hides in nebulae and ambushes passersby.', 'raid', 'common', 7500, 115, 45, 35, '["Nebula Cloak", "Acid Spray"]'::jsonb, '{"explosive": 1.4}'::jsonb, '{"energy": 0.6}'::jsonb, '[{"item": "nebula_tissue", "quantity": 2, "dropRate": 0.55}]'::jsonb, '{"xp": 210, "credits": 450, "resources": {"metal": 60, "crystal": 90}}'::jsonb, 8, 1, 1),
