('Void Tendril', 'A grasping appendage of a larger void entity that lurks just beyond sensor range.', 'raid', 'common', 7800, 100, 35, 45, '["Grapple", "Void Drain"]'::jsonb, '{"kinetic": 1.5}'::jsonb, '{"energy": 0.7}'::jsonb, '[{"item": "void_fiber", "quantity": 3, "dropRate": 0.65}]'::jsonb, '{"xp": 200, "credits": 400, "resources": {"metal": 50, "crystal": 50, "deuterium": 30}}'::jsonb, 7, 1, 1),
