('Wreckage Swarm', 'Hundreds of tiny ship fragments held together by magnetic fields forming a hostile mass.', 'raid', 'common', 8200, 110, 40, 35, '["Debris Storm", "Magnetic Pull"]'::jsonb, '{"explosive": 1.4}'::jsonb, '{"kinetic": 0.5}'::jsonb, '[{"item": "hull_fragment", "quantity": 5, "dropRate": 0.8}]'::jsonb, '{"xp": 220, "credits": 480, "resources": {"metal": 130, "crystal": 20}}'::jsonb, 8, 1, 1);
